INSERT INTO `cms_pages` (`cms_id`, `cms_page_name`, `cms_slug`, `cms_image`, `cms_page_heading`, `cms_page_small_description`, `cms_page_description`) VALUES
(1, 'About Us', '', '1719382750_6232d2d7cfb065a53fa1.png', 'OUR STORY', 'OUR STORY', '<h3 style=\"text-align:justify\"><strong>Welcome to Heywansaa &mdash; Where Every Product Tells a Story</strong></h3>\r\n\r\n<p style=\"text-align:justify\">At <strong>Heywansaa</strong>, we believe every corner of India has a story to tell &mdash; through its art, culture, and traditions. Our mission is to bring those stories closer to you.</p>\r\n\r\n<p style=\"text-align:justify\">We are not just an e-commerce platform &mdash; we are a celebration of India&rsquo;s diversity. From the intricate handiwork of local artisans to the unique items used in cultural festivals, we connect you directly with passionate vendors from every state. Each product you find here is lovingly crafted or curated by the people who know their culture best &mdash; the locals themselves.</p>\r\n\r\n<p style=\"text-align:justify\">When you buy from Heywansaa, you&rsquo;re not just making a purchase &mdash; you&rsquo;re supporting small businesses, preserving heritage, and becoming part of a beautiful journey that keeps India&rsquo;s traditions alive, one order at a time.</p>\r\n\r\n<p style=\"text-align:justify\">Let&rsquo;s celebrate India&rsquo;s heart and soul &mdash; together, with <strong>Heywansaa</strong>.<br />\r\n<strong>Welcome to Heywansaa &mdash; where the world shops with heart.</strong></p>\r\n'),
(5, 'About Us', '', '1719382862_74800b06e98418b88994.jpg', 'Free Shipping', 'Enjoy fast, reliable delivery straight to your doorstep â always secure, always hassle-free. No hidden fees, just free shipping on orders over a certain amount.                                                                                  ', '<p>Lorem Ipsum is simply dummy text of the printing and typesetting industry. Lorem Ipsum has been the industr.</p>\r\n'),
(6, 'About Us', '', '1719382891_f095aec7cc019004202e.jpg', '100% Money Back Guarantee', 'Your satisfaction means everything to us. If our service doesnât meet your expectations, youâre covered by our full refund guarantee â no hassle, no risk. See our Return and Refund Policy for details.', '<p>Lorem Ipsum is simply dummy text of the printing and typesetting industry. Lorem Ipsum has been the industr.</p>\r\n'),
(7, 'About Us', '', '1719382926_7997e882404d2c8622b4.jpg', 'Support 24/7 Hours ', 'Lorem Ipsum is simply dummy text of the printing and typesetting industry. Lorem Ipsum has been the industr.', '<p>Lorem Ipsum is simply dummy text of the printing and typesetting industry. Lorem Ipsum has been the industr.</p>\r\n'),
(15, 'Home', '', '1738748968_b6a90d79aef71603266c.png', 'Bringing India\'s local heritage to your doorstep - Curated by artisans statewise ', 'https://ase-electrical.co.uk/newecom/', '<h2 style=\"text-align:justify\"><span style=\"font-family:Comic Sans MS,cursive\"><span style=\"font-size:14px\">Discover unique finds starting at 99.&nbsp;&nbsp;<img alt=\"heart\" src=\"https://snindustries.org/newecom/assets/admin/ckeditor/plugins/smiley/images/heart.png\" style=\"height:23px; width:23px\" title=\"heart\" /></span></span><br />\r\n<span style=\"font-family:Comic Sans MS,cursive\"><span style=\"font-size:14px\">Start your shopping journey with joy and confidence at Heywansaa</span></span></h2>\r\n'),
(16, 'Home', '', '1738749411_8bd0f425c1cfafa202ce.jpg', 'Flash Sale', 'https://ase-electrical.co.uk/newecom/', '<h3>ALL HIGH PERFORMANCE<br />\r\nWHEELS AND TIRES</h3>\r\n\r\n<h2>Starting<br />\r\nat&nbsp;<small>?</small>199<small>99</small></h2>\r\n'),
