(18, 'Home', '', '1738749828_c3568e39cdb8f42d4d37.jpg', 'Outlet Selected Items', 'big sale up to <br> 70% OFF', ''),
(19, 'Home', '', '1738750372_29a2f412d76b62e72975.jpg', 'Big sale', 'https://ase-electrical.co.uk/newecom/', '<p>ALL HIGH PERFORMANCE ITEMS UP TO 70% OFF</p>\r\n'),
