(37, 'Footer', '', '', 'Footer', 'Welcome to Heywansaa <br> where the world comes together to shop, share, and celebrate diversity.', ''),
(38, 'Terms & Conditions ', 'terms-and-conditions', '', 'Terms & Condition', 'Terms & Condition', '<h3><strong>1. Acceptance and Acknowledgement</strong></h3>\r\n\r\n<p>By accessing and using <strong>heywansaa.com</strong> and any of its subdomains, you agree to be bound by the Terms of Service set forth herein. By completing the registration process, you acknowledge that you have read, understood, and agreed to comply with all the terms, conditions, and policies governing the use of the platform.</p>\r\n\r\n<hr />\r\n<h3><strong>2. Use of the Website</strong></h3>\r\n\r\n<p>Unauthorized use of this website is strictly prohibited. By using heywansaa.com, you affirm that:</p>\r\n\r\n<ul>\r\n	<li>\r\n	<p>(a) All information provided during registration is <strong>accurate, complete, and current</strong>.</p>\r\n	</li>\r\n	<li>\r\n	<p>(b) You are <strong>at least 18 years of age</strong> or older.</p>\r\n	</li>\r\n	<li>\r\n	<p>(c) You are solely responsible for maintaining the <strong>accuracy and security</strong> of your account information.</p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<h3><strong>3. Prohibited Content</strong></h3>\r\n\r\n<p>Heywansaa.com retains full and exclusive rights to determine what content may be displayed or removed from the website, without prior notice. Users are strictly prohibited from posting or sharing any of the following types of content:</p>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Content that includes <strong>nudity, violence, offensive language</strong>, or themes related to adult material.</p>\r\n	</li>\r\n	<li>\r\n	<p>Content that is <strong>harassing, abusive, or threatening</strong> in nature.</p>\r\n	</li>\r\n	<li>\r\n	<p>Content that exploits individuals in a <strong>sexual or violent</strong> manner.</p>\r\n	</li>\r\n	<li>\r\n	<p>Content containing <strong>ethnically, racially, or otherwise objectionable</strong> language.</p>\r\n	</li>\r\n	<li>\r\n	<p>Content classified as <strong>spam, junk mail</strong>, or unauthorized advertising.</p>\r\n	</li>\r\n	<li>\r\n	<p>Content that solicits <strong>passwords or personal information</strong> from other users.</p>\r\n	</li>\r\n	<li>\r\n	<p>Content that infringes upon the <strong>rights of any third-party</strong>.</p>\r\n	</li>\r\n	<li>\r\n	<p>Content promoting <strong>sales, commercial activities</strong>, or unauthorized transactions.</p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<h3><strong>4. Account Security</strong></h3>\r\n\r\n<p>Users are solely responsible for maintaining the confidentiality of their login credentials, including username and password, created during the registration process. You are fully accountable for all activities conducted through your account.</p>\r\n\r\n<p>We strongly recommend that you <strong>log out</strong> of your account after each session, especially when accessing the website from shared or public devices.</p>\r\n\r\n<hr />\r\n<h3><strong>5. Notifications</strong></h3>\r\n\r\n<p>Heywansaa.com may provide important notifications regarding your account or updates to these Terms of Service via email or through other communication methods. It is your responsibility to ensure that your contact information remains accurate and up to date.</p>\r\n\r\n<hr />\r\n<h3><strong>6. Termination of Services</strong></h3>\r\n\r\n<p>You may discontinue the use of heywansaa.com and its services at any time should you choose to do so. If you experience any issues or have concerns, we encourage you to contact our <strong>Customer Support Team</strong> for assistance.</p>\r\n\r\n<hr />\r\n<h3><strong>Contact Information</strong></h3>\r\n\r\n<p>For any queries regarding these Terms of Service, please reach out to us at:</p>\r\n\r\n<p><strong>Email:</strong> info@heywansaa.com</p>\r\n'),
(39, 'Privacy Policy ', 'privacy-policy', '', 'Privacy Policy', '.', '<h4 style=\"text-align:justify\">At Heywansaa, accessible via www.heywansaa.com, we are committed to protecting your privacy and ensuring that your personal information is handled in a safe and responsible manner. This Privacy Policy outlines how we collect, use, and protect the personal data you provide to us. It reflects our dedication to maintaining transparency and building trust with our users.</h4>\r\n\r\n<h3><strong>1. Information We Collect</strong></h3>\r\n\r\n<p>When you register on our website to access our services, you may be required to submit personal details including your:</p>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Full name</p>\r\n	</li>\r\n	<li>\r\n	<p>Email address</p>\r\n	</li>\r\n	<li>\r\n	<p>Phone number</p>\r\n	</li>\r\n	<li>\r\n	<p>Physical address</p>\r\n	</li>\r\n</ul>\r\n\r\n<p>We collect this information for the following purposes:</p>\r\n\r\n<ul>\r\n	<li>\r\n	<p>To personalize the content you see on our website</p>\r\n	</li>\r\n	<li>\r\n	<p>To contact you regarding the services you have selected</p>\r\n	</li>\r\n	<li>\r\n	<p>To request feedback or offer additional services that may be relevant to your needs</p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<h3><strong>2. Use of Cookies</strong></h3>\r\n\r\n<p>We use cookies to enhance your browsing experience and to help us improve our website. Cookies allow us to collect data such as your IP address, location, browser type, and usage patterns. This information enables us to:</p>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Analyze website traffic and user behavior</p>\r\n	</li>\r\n	<li>\r\n	<p>Serve relevant content tailored to your interests</p>\r\n	</li>\r\n	<li>\r\n	<p>Improve the functionality and performance of our site</p>\r\n	</li>\r\n</ul>\r\n\r\n<p>Please note:</p>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Cookies do <strong>not</strong> collect personal information.</p>\r\n	</li>\r\n	<li>\r\n	<p>You have the option to accept or reject cookies through your browser settings. However, disabling cookies may affect the performance and functionality of some parts of the website.</p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<h3><strong>3. Account and Password Security</strong></h3>\r\n\r\n<p>You are solely responsible for maintaining the confidentiality of your login ID and password. All activities carried out using your credentials are considered your responsibility, including any associated charges.</p>\r\n\r\n<p>We strongly advise you <strong>not</strong> to share your login details with any third party. If you suspect that your password has been compromised or you notice any unauthorized activity on your account, please update your password immediately.</p>\r\n\r\n<hr />\r\n<h3><strong>4. Third-Party Links</strong></h3>\r\n\r\n<p>Our website may contain links to third-party websites. These external sites operate independently and have their own privacy policies and terms of service. We do <strong>not</strong> accept any responsibility or liability for their content or handling of your personal information.</p>\r\n\r\n<p><strong>We strongly recommend that you review the privacy policy of any third-party site before providing any personal data.</strong></p>\r\n\r\n<hr />\r\n<h3><strong>5. Updates to This Privacy Policy</strong></h3>\r\n\r\n<p>Heywansaa reserves the right to update or modify this Privacy Policy at any time without prior notice. Any changes will be reflected on this page, and we encourage you to review the policy periodically to stay informed about how we are protecting your information.</p>\r\n\r\n<hr />\r\n<h3><strong>6. Access to Your Information</strong></h3>\r\n\r\n<p>In accordance with the Information Technology Act, 2000, you have the right to request access to any personal data we hold about you. Please note that we reserve the right to charge a reasonable fee to cover the administrative costs involved in providing such information.</p>\r\n\r\n<hr />\r\n<h3><strong>7. Governing Law</strong></h3>\r\n\r\n<p>This Privacy Policy is governed by and construed in accordance with the laws of the <strong>Government of India</strong>. By using our website, you agree to submit to the exclusive jurisdiction of the Indian legal system in relation to any dispute arising under or in connection with this policy.</p>\r\n\r\n<hr />\r\n<h3><strong>8. Contact Us</strong></h3>\r\n\r\n<p>If you have any questions, concerns, or requests regarding this Privacy Policy, please contact us at:</p>\r\n\r\n<p><strong>Email:</strong> info@heywansaa.com</p>\r\n\r\n<h4>&nbsp;</h4>\r\n'),
(40, 'Return Policy ', 'return-policy', '', 'Return Policy ', 'Return Policy ', '<h3><strong>Order Cancellation</strong></h3>\r\n\r\n<p style=\"text-align:justify\">Once an order has been confirmed, acknowledged, and processed, it <strong>cannot be cancelled</strong> under any circumstances.</p>\r\n\r\n<p style=\"text-align:justify\">If you have placed an order by mistake or no longer wish to proceed with the purchase, you may request cancellation by contacting our <strong>Customer Support Team</strong> within <strong>30 minutes</strong> of placing the order, <strong>provided the product has not been accessed, used, or downloaded</strong> (for digital services or products, if applicable).</p>\r\n\r\n<p style=\"text-align:justify\">All cancellation requests made beyond this time frame or after order processing will <strong>not be entertained</strong>.</p>\r\n\r\n<hr />\r\n<h3><strong>Returns and Refunds</strong></h3>\r\n\r\n<p style=\"text-align:justify\">We do not accept return or refund requests once an order has been acknowledged and processed.</p>\r\n\r\n<p style=\"text-align:justify\">However, in the event that an <strong>incorrect or defective product</strong> has been delivered, customers are entitled to raise a return request by contacting our Customer Support within <strong>24 hours of receiving the product</strong>.</p>\r\n\r\n<p style=\"text-align:justify\">To be eligible for a return:</p>\r\n\r\n<ul>\r\n	<li>\r\n	<p style=\"text-align:justify\">The product must be in its <strong>original condition</strong>, unused, and in the <strong>same packaging</strong> as delivered.</p>\r\n	</li>\r\n	<li>\r\n	<p style=\"text-align:justify\">The return must be initiated within the stipulated 24-hour timeframe.</p>\r\n	</li>\r\n	<li>\r\n	<p style=\"text-align:justify\">We reserve the right to <strong>decline the return</strong> if the product is found to be used, damaged after delivery, or not in the condition it was originally shipped.</p>\r\n	</li>\r\n</ul>\r\n\r\n<p style=\"text-align:justify\"><strong>Refunds</strong> will be processed only after the returned product is received and verified by our team. Once approved, the refund will be initiated and credited to the customer&rsquo;s original payment method within <strong>7&ndash;10 business days</strong>.</p>\r\n\r\n<hr />\r\n<h3><strong>Need Assistance?</strong></h3>\r\n\r\n<p>For any queries or assistance related to cancellation, returns, or refunds, please contact our <strong>Customer Support</strong> at:</p>\r\n\r\n<p><strong>Email:</strong> info@heywansaa.com</p>\r\n');
