(29, 'Nishant\'s  buds', 10, 0, '', 'earbuds.jpg', 'nishants-buds', 200.00, 100.00, 'Yes', 0.00, 589, '', '<p>Highlights</p>\r\n\r\n<ul>\r\n	<li>With Mic:Yes</li>\r\n	<li>Bluetooth version: 5.3</li>\r\n	<li>Zen ENC mic for crystal-clear voice calls and communication.</li>\r\n	<li>Impressive 35 Hrs battery life for extended listening sessions.</li>\r\n	<li>Lightning Boultï¿½ Type C Fast Charging, 10 mins = 120 mins Playtime.</li>\r\n	<li>45ms Ultra-Low Latency Gaming | BoomX Tech for Supreme Bass.</li>\r\n	<li>Bluetooth version 5.3 | 10m connectivity range | 13mm Drivers.</li>\r\n	<li>IPX5 Water Resistant | Voice Assistant | Touch Control.</li>\r\n	<li>Proudly Made in India, supporting local manufacturing and expertise.</li>\r\n</ul>\r\n', '<p>Carry your Pocket Pulse wherever you go - Introducing Boult W20 earbuds. Enjoy an extended 35-hour playtime, ensuring your music never misses a beat. Get back in the game in no time thanks to the Lightning Boultï¿½ type C fast charging that grants 120 minutes of playtime with just 10 minutes of charging. Elevate your gaming with Combatï¿½ gaming mode, featuring 45ms ultra-low latency for a seamless, competitive edge. Immerse in exceptional sound through BoomXï¿½ technology powered by 13mm drivers, delivering an audio experience beyond excellent. Experience crisp and clear calling with Zenï¿½ ENC mic, perfect for calls and coordination. Swiftly connect via Blink &amp; Pairï¿½ and Bluetooth 5.3 technology, ensuring the fastest pairing for instant audio gratification. Choose your style from Space Black, Pine Green, and Glacier Blue colour variants. With IPX5 Water Resistance, these earbuds keep up with your active lifestyle. Your Pocket Pulse is here ï¿½ embrace it with Boult W20 earbuds.</p>\r\n', '<p>Specifications</p>\r\n\r\n<p>General</p>\r\n\r\n<table>\r\n	<tbody>\r\n		<tr>\r\n			<td>Model ID</td>\r\n			<td>\r\n			<ul>\r\n				<li>W20</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Color</td>\r\n			<td>\r\n			<ul>\r\n				<li>Glacier Blue</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Headphone Type</td>\r\n			<td>\r\n			<ul>\r\n				<li>True Wireless</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Inline Remote</td>\r\n			<td>\r\n			<ul>\r\n				<li>Yes</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Sales Package</td>\r\n			<td>\r\n			<ul>\r\n				<li>1 Pair of Earbuds, Charging Case, Charging Cable, User Manual, Warranty Card, Additional Pair of Ear Tips</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Connectivity</td>\r\n			<td>\r\n			<ul>\r\n				<li>Bluetooth</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Headphone Design</td>\r\n			<td>\r\n			<ul>\r\n				<li>Earbud</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Compatible Devices</td>\r\n			<td>\r\n			<ul>\r\n				<li>Laptop, Mobile, Tablet, Desktop</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<p>Product Details</p>\r\n\r\n<table>\r\n	<tbody>\r\n		<tr>\r\n			<td>Sweat Proof</td>\r\n			<td>\r\n			<ul>\r\n				<li>Yes</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Deep Bass</td>\r\n			<td>\r\n			<ul>\r\n				<li>Yes</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Water Resistant</td>\r\n			<td>\r\n			<ul>\r\n				<li>Yes</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Driver Type</td>\r\n			<td>\r\n			<ul>\r\n				<li>Dynamic</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Headphone Driver Units</td>\r\n			<td>\r\n			<ul>\r\n				<li>13 mm</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>With Microphone</td>\r\n			<td>\r\n			<ul>\r\n				<li>Yes</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<p>Sound Features</p>\r\n\r\n<table>\r\n	<tbody>\r\n		<tr>\r\n			<td>Impedance</td>\r\n			<td>\r\n			<ul>\r\n				<li>16 ohm</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Signal to Noise Ratio</td>\r\n			<td>\r\n			<ul>\r\n				<li>90 dB</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<p>Connectivity Features</p>\r\n\r\n<table>\r\n	<tbody>\r\n		<tr>\r\n			<td>Wireless Range</td>\r\n			<td>\r\n			<ul>\r\n				<li>10 m</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Bluetooth Version</td>\r\n			<td>\r\n			<ul>\r\n				<li>5.3</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<p>Warranty</p>\r\n\r\n<table>\r\n	<tbody>\r\n		<tr>\r\n			<td>Domestic Warranty</td>\r\n			<td>\r\n			<ul>\r\n				<li>1 Year</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Warranty Summary</td>\r\n			<td>\r\n			<ul>\r\n				<li>1 Year Warranty</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Warranty Service Type</td>\r\n			<td>\r\n			<ul>\r\n				<li>support@boultaudio.com 9555 - 602- 502</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Covered in Warranty</td>\r\n			<td>\r\n			<ul>\r\n				<li>Manufacturing Defects</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Not Covered in Warranty</td>\r\n			<td>\r\n			<ul>\r\n				<li>Physical Damages</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n', 'Inactive', 'danger', '', 'hv', 'jfhv.ou', '2026-06-28 00:00:00', 1),
