(34, 'Handmade Kids Bookmark', 4, 1, '', 'WhatsApp Image 2026-01-03 at 2.50.10 PM.jpeg', 'handmade-kids-bookmark', 100.00, 20.00, 'Yes', 0.00, 1, '', '<p>Handmade Kids Bookmark | Creative &amp; Colorful Page Marker | Unique Child-Made Bookmark for Books &amp; Journals</p>\r\n', '<p>Add a touch of innocence and creativity to your reading time with this beautiful handmade bookmark crafted by a child. Each bookmark is thoughtfully designed using vibrant colors and imaginative ideas, making every piece unique and full of character.<br />\r\nPerfect for students, book lovers, and gifting, this bookmark not only marks your page but also celebrates a child&rsquo;s creativity and love for art. Slight variations in design make each bookmark special&mdash;no two are exactly the same.<br />\r\nBy choosing this bookmark, you&rsquo;re encouraging creativity, learning, and confidence in young minds while owning a truly one-of-a-kind handmade product.<br />\r\nKey Highlights&nbsp;<br />\r\nâ¨ Handmade by a child &ndash; pure creativity and originality<br />\r\n???? Ideal for books, notebooks, journals &amp; planners<br />\r\n???? Bright colors &amp; playful design<br />\r\n???? Perfect as a gift for kids, students &amp; readers<br />\r\n???? Lightweight and strong</p>\r\n', '', 'Inactive', 'danger', '', 'Handmade Book Mark', 'Handmade Book Mark', '2026-06-28 00:00:00', 24),
(35, 'test', 1, 1, '5', 'images.png', 'test', 1500.00, 1000.00, 'Yes', 0.00, 10, 'test1234', '<p>test</p>\r\n', '<p>test</p>\r\n', '<p>test</p>\r\n', 'Inactive', 'danger', 'test pc build', 'test', 'test', '2026-01-28 00:00:00', 27),
